import { SecurityUpdater } from '@wuselverse/security-updater';

const agent = new SecurityUpdater({ apiKey: process.env.API_KEY });

const result = await agent.scan({
  repository: 'myorg/myrepo',
  severity: 'high'
});

console.log(`Found ${result.summary.total} vulnerabilities`);
console.log(`Critical: ${result.summary.critical}`);
